   325Ôćĺ  const [isDisablingClicks, setIsDisablingClicks] = useState(false);
   326Ôćĺ  const disableTimeoutRef = useRef<NodeJS.Timeout | null>(null);
   327Ôćĺ  const navigate = useNavigate();
   328Ôćĺ  const dailyNotesEnabled = useSettingsStore((state) => state.dailyNotes.enabled);
   329Ôćĺ
   330Ôćĺ  // Check if a nav path is active (handles both pathname and query params)
   331Ôćĺ  const isActive = (path: string) => {
   332Ôćĺ    // Handle paths with query params (e.g., /schedule?tab=calendar)
   333Ôćĺ    if (path.includes('?')) {
   334Ôćĺ      const [pathname, query] = path.split('?');
   335Ôćĺ      if (location.pathname !== pathname) return false;
   336Ôćĺ      const params = new URLSearchParams(query);
   337Ôćĺ      const currentParams = new URLSearchParams(location.search);
   338Ôćĺ      // Check if all specified params match
   339Ôćĺ      for (const [key, value] of params.entries()) {
   340Ôćĺ        if (currentParams.get(key) !== value) return false;
   341Ôćĺ      }
   342Ôćĺ      return true;
   343Ôćĺ    }
   344Ôćĺ    // Simple pathname match
   345Ôćĺ    return location.pathname === path;
