import { DndContext, closestCenter, PointerSensor, useSensor, useSensors } from '@dnd-kit/core';
import type { DragEndEvent } from '@dnd-kit/core';
import { SortableContext, verticalListSortingStrategy, useSortable, arrayMove } from '@dnd-kit/sortable';
import { CSS } from '@dnd-kit/utilities';

// Lazy load sidebar panels to reduce initial bundle
const PageSettingsPanel = lazy(() => import('./PageSettingsPanel').then(m => ({ default: m.PageSettingsPanel })));
const TimeTrackingPanel = lazy(() => import('./TimeTrackingPanel').then(m => ({ default: m.TimeTrackingPanel })));

/**
 * FOUNDATIONAL: NavItem interface with expandable support
 * Any nav item can have sub-pages by adding `children`.
 */
interface NavItem {
  icon: string;
  label: string;
  path: string;
  shortcut?: string;
  hasSettings?: boolean; // Whether this page has custom settings
  children?: NavItem[]; // Sub-pages (expandable)
  defaultExpanded?: boolean; // Initial expansion state
}

// Fixed navigation items (always at top, not draggable)
const fixedNavigation: NavItem[] = [
  {
    icon: '­čĆá',
    label: 'Dashboard',
    path: '/',
    shortcut: 'D',
    hasSettings: true,
    defaultExpanded: true,
    children: [
      { icon: '­čôć', label: 'Today', path: '/today' },
      { icon: '­čöŚ', label: 'Link Library', path: '/links' },
    ],
  },
];

// Draggable navigation items (user can reorganize)
const draggableNavigation: NavItem[] = [
  {
    icon: '­čôů',
    label: 'Schedule',
    path: '/schedule',
    shortcut: 'P',
    hasSettings: false,
    defaultExpanded: false,
    children: [
      { icon: 'ÔĆ▒´ŞĆ', label: 'Timer', path: '/schedule?tab=timer' },
      { icon: '­čôő', label: 'Entries', path: '/schedule?tab=entries' },
      { icon: '­čôŐ', label: 'Summary', path: '/schedule?tab=summary' },
      { icon: '­čôć', label: 'Calendar', path: '/schedule?tab=calendar' },
      { icon: '­čôü', label: 'Projects', path: '/schedule?tab=projects' },
      { icon: '­čôä', label: 'Invoices', path: '/schedule?tab=invoices' },
      { icon: '­čôł', label: 'Reports', path: '/schedule?tab=reports' },
      { icon: '­čŹů', label: 'Pomodoro', path: '/schedule?tab=pomodoro' },
      { icon: '­čôŹ', label: 'Timeline', path: '/schedule?tab=timeline' },
      { icon: 'ÔÜÖ´ŞĆ', label: 'Settings', path: '/schedule?tab=settings' },
    ],
  },
  {
    icon: '­čôŁ',
    label: 'Notes',
    path: '/notes',
    shortcut: 'N',
    hasSettings: false,
    defaultExpanded: false,
    children: [
      { icon: '­čôů', label: 'Daily Notes', path: '/notes?daily=true' },
      { icon: '­čĽŞ´ŞĆ', label: 'Graph', path: '/graph' },
      { icon: '­čôŐ', label: 'Diagrams', path: '/diagrams' },
      { icon: '­čôő', label: 'Forms', path: '/forms' },
    ],
  },
  {
    icon: 'Ôťô',
    label: 'Tasks',
    path: '/tasks',
    shortcut: 'T',
    hasSettings: false,
    defaultExpanded: false,
    children: [
      { icon: '­čôő', label: 'Kanban', path: '/tasks?view=kanban' },
